const d = $input.item.json.body || $input.item.json;
const required = ['userId', 'symbol', 'strategy', 'startDate', 'endDate'];
const missing = required.filter(k => !d[k]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const startDate = new Date(d.startDate);
const endDate = new Date(d.endDate);
const daysDiff = (endDate - startDate) / (1000 * 60 * 60 * 24);

if (daysDiff < 30) throw new Error('Backtest period must be at least 30 days');
if (daysDiff > 1825) throw new Error('Backtest period cannot exceed 5 years');

return [{
  json: {
    ...d,
    backtestId: `bt_${Date.now()}_${d.userId}`,
    status: 'queued',
    estimatedMinutes: Math.ceil(daysDiff / 365) * 2,
    queuedAt: new Date().toISOString()
  }
}];

const d = $input.item.json;
const symbol = d.symbol;
const startTs = Math.floor(new Date(d.startDate).getTime() / 1000);
const endTs = Math.floor(new Date(d.endDate).getTime() / 1000);

try {
  const url = `https://query1.finance.yahoo.com/v8/finance/chart/${symbol}?interval=1d&period1=${startTs}&period2=${endTs}`;
  const res = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0' } });
  const data = await res.json();
  const result = data.chart?.result?.[0];

  if (!result) throw new Error('No data returned');

  const timestamps = result.timestamp || [];
  const quotes = result.indicators?.quote?.[0] || {};

  const candles = timestamps.map((ts, i) => ({
    date: new Date(ts * 1000).toISOString().split('T')[0],
    open: quotes.open?.[i],
    high: quotes.high?.[i],
    low: quotes.low?.[i],
    close: quotes.close?.[i],
    volume: quotes.volume?.[i]
  })).filter(c => c.close != null);

  return [{ json: { ...d, candles, candleCount: candles.length } }];
} catch(e) {
  return [{ json: { ...d, error: e.message, candles: [] } }];
}
